# ❌ ANTI-PATTERN: Single metric dependency
class BowlerPerformanceEval:
    def evaluate_match(self, deliveries):
        # Only tracks economy rate—misses consistency
        economy = sum(runs) / overs_bowled
        return {"economy_rate": economy}

    def make_selection_decision(self, economy):
        if economy < 7.5:
            return "SELECT_BOWLER"
        # Brittles on one metric; misses 4-wicket spells at 8.2 economy
        return "REJECT"

# ✅ BEST PRACTICE: Multi-metric evaluation with tier gating
class BowlerPerformanceEval:
    def __init__(self):
        self.threshold_gate = {"economy": 8.5, "wickets": 0.5, "dot_ball_pct": 35}
        self.human_review_threshold = 0.65  # Confidence score

    def evaluate_match(self, deliveries, match_context):
        # Tier 1: Automatic metrics
        economy = sum(runs) / overs_bowled
        wicket_rate = wickets / overs_bowled
        dot_percentage = dots / deliveries

        # Tier 2: Context-aware filtering
        confidence = self._compute_confidence(
            economy, wicket_rate, dot_percentage, match_context
        )

        if confidence > self.human_review_threshold:
            return {"decision": "AUTO_SELECT", "metrics": {
                "economy": economy,
                "wicket_rate": wicket_rate,
                "dot_pct": dot_percentage,
                "confidence": confidence
            }}
        else:
            return {"decision": "HUMAN_REVIEW", "metrics": {
                "economy": economy,
                "wicket_rate": wicket_rate,
                "context_flags": match_context["stage"]  # death overs, powerplay, etc.
            }}

    def _compute_confidence(self, economy, wicket_rate, dot_pct, context):
        # Ensemble: weighted combination of normalized metrics
        normalized_economy = 1 - (economy / 10)  # Lower is better
        normalized_wickets = min(wicket_rate / 1.0, 1.0)  # Higher is better
        normalized_dots = dot_pct / 100

        # Context-aware weighting: death overs prioritize dot balls
        weights = {
            "powerplay": {"economy": 0.3, "wickets": 0.4, "dots": 0.3},
            "middle": {"economy": 0.4, "wickets": 0.3, "dots": 0.3},
            "death": {"economy": 0.2, "wickets": 0.3, "dots": 0.5}
        }
        w = weights.get(context.get("stage"), weights["middle"])

        confidence = (
            w["economy"] * normalized_economy +
            w["wickets"] * normalized_wickets +
            w["dots"] * normalized_dots
        )
        return confidence
